from flask import Flask, request, jsonify
import psycopg2
from psycopg2.extras import RealDictCursor

app = Flask(__name__)

DB_CONFIG = {
    "host": "localhost",
    "port": 5432,
    "dbname": "analytics",
    "user": "postgres",
    "password": "postgres",
}

def get_connection():
    return psycopg2.connect(**DB_CONFIG)

@app.route("/query", methods=["POST"])
def dynamic_query():
    data = request.get_json(force=True)

    table = data.get("table")
    columns = data.get("columns", ["*"])
    filters = data.get("filters", {})
    limit = data.get("limit")

    if not table:
        return jsonify({"error": "table is required"}), 400

    column_sql = ", ".join(columns) if columns else "*"
    sql = f"SELECT {column_sql} FROM {table}"

    values = []
    if filters:
        conditions = []
        for key, value in filters.items():
            conditions.append(f"{key} = %s")
            values.append(value)
        sql += " WHERE " + " AND ".join(conditions)

    if limit is not None:
        sql += f" LIMIT {int(limit)}"

    try:
        conn = get_connection()
        cur = conn.cursor(cursor_factory=RealDictCursor)
        cur.execute(sql, values)
        rows = cur.fetchall()
        cur.close()
        conn.close()
        return jsonify({"query": sql, "params": values, "results": rows})
    except Exception as e:
        return jsonify({"error": str(e), "query": sql}), 500

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000, debug=True)